type carClassesToCarModelJoins[Q dialect.Joinable] struct {
	typ      string
	CarClass modAs[Q, carClassColumns]
	CarModel modAs[Q, carModelColumns]
}

func (j carClassesToCarModelJoins[Q]) aliasedAs(alias string) carClassesToCarModelJoins[Q] {
	return buildCarClassesToCarModelJoins[Q](buildCarClassesToCarModelColumns(alias), j.typ)
}

func buildCarClassesToCarModelJoins[Q dialect.Joinable](cols carClassesToCarModelColumns, typ string) carClassesToCarModelJoins[Q] {
	return carClassesToCarModelJoins[Q]{
		typ: typ,
		CarClass: modAs[Q, carClassColumns]{
			c: CarClasses.Columns,
			f: func(to carClassColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarClasses.Name().As(to.Alias())).On(
						to.ID.EQ(cols.CarClassID),
					))
				}

				return mods
			},
		},
		CarModel: modAs[Q, carModelColumns]{
			c: CarModels.Columns,
			f: func(to carModelColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarModels.Name().As(to.Alias())).On(
						to.ID.EQ(cols.CarModelID),
					))
				}

				return mods
			},
		},
	}
}
